const json = $input.item.json;
const body = json.body || json;
const message = body.message || json.message || '';

const normalizeText = (text) => String(text)
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/\s+/g, ' ')
  .trim();

const domainCorrections = {
  contratt: 'contrat',
  pcaa: 'pca',
  poo: 'po'
};

const correctedMessage = String(message)
  .split(' ')
  .map((word) => domainCorrections[word] || word)
  .join(' ');

return {
  json: {
    userMessage: normalizeText(correctedMessage),
    userId: body.userId || json.userId,
    conversationId: body.conversationId || json.conversationId
  }
};

const raw = $input.first().json;
let payload = raw.body ?? raw;
if (typeof payload === 'string') {
  try {
    payload = JSON.parse(payload);
  } catch {
    payload = {};
  }
}

const hits = Array.isArray(payload?.data?.hits) ? payload.data.hits : [];
const searchOk = payload?.success !== false;
const searchError =
  searchOk ? null : (payload?.error || payload?.message || 'Échec de la recherche');

const TOP = 5;
const top = hits.slice(0, TOP);

const lines = top.map((h, i) => {
  const title = h.title || '';
  const folder = h.folder || '';
  const url = h.url || '';
  return `${i + 1}. ${title}\n   Dossier: ${folder}\n   Lien: ${url}`;
});

const contextForModel =
  top.length > 0
    ? `Documents SharePoint (métadonnées seulement — pas le texte des fichiers). Tu dois brièvement décrire ces documents et inviter à ouvrir les liens. Ne dis jamais qu'il n'y a « aucune information » si cette liste est non vide.\n\n${lines.join('\n\n')}`
    : '';

const sources = top.map((h) => ({
  title: h.title || '',
  url: h.url || '#',
  snippet: String(h.folder || '').slice(0, 200)
}));

let userMessage = '';
try {
  userMessage = $('Validate & Normalize Input').first().json.userMessage || '';
} catch (_) {}

const hasResults = searchOk && top.length > 0;

return [
  {
    json: {
      contextForModel,
      sources,
      hasResults,
      userMessage,
      totalHits: hits.length,
      returnedCount: top.length,
      searchOk,
      searchError
    }
  }
];

const j = $input.first().json;

if (j.searchError) {
  return [
    {
      json: {
        success: true,
        response:
          "La recherche de documents est temporairement indisponible. Merci de réessayer dans un instant.",
        metadata: {
          sources: [],
          hasResults: false,
          totalHits: 0,
          error: j.searchError,
          timestamp: new Date().toISOString()
        }
      }
    }
  ];
}

return [
  {
    json: {
      success: true,
      response:
        "Je n'ai trouvé aucun document SharePoint correspondant à votre recherche. Essayez d'autres mots-clés ou précisez le dossier ou le type de document.",
      metadata: {
        sources: [],
        hasResults: false,
        totalHits: 0,
        timestamp: new Date().toISOString()
      }
    }
  }
];

