const geminiResponse = $input.first().json;
let aiResponse = 'Information indisponible';

if (geminiResponse?.candidates?.[0]?.content?.parts?.[0]?.text) {
  aiResponse = geminiResponse.candidates[0].content.parts[0].text;
}

let sources = [];
let hasResults = false;
let totalHits = 0;

try {
  const s = $('Process Search Results1').first().json;
  sources = s.sources || [];
  hasResults = s.hasResults || false;
  totalHits = s.totalHits || 0;
} catch (_) {}

return {
  json: {
    success: true,
    response: aiResponse,
    metadata: {
      sources,
      hasResults,
      totalHits,
      timestamp: new Date().toISOString()
    }
  }
};
